parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "workflow_state": {
      "type": "string",
      "enum": ["initial_contact", "intent_identified", "entity_collection", "validation_pending", "action_authorized", "action_blocked", "escalation_required", "completed"],
      "description": "Current state in the workflow state machine"
    },
    "intent": {
      "type": "string",
      "enum": ["appointment_request", "appointment_cancel", "appointment_reschedule", "medication_inquiry", "general_question", "emergency_indicator", "consent_verification", "identity_verification", "unknown"],
      "description": "Identified patient intent"
    },
    "entities": {
      "type": "object",
      "properties": {
        "patient_name": {"type": "string"},
        "date_time": {"type": "string", "format": "date-time"},
        "department": {"type": "string"},
        "doctor_name": {"type": "string"},
        "appointment_id": {"type": "string"},
        "symptoms": {"type": "array", "items": {"type": "string"}},
        "medication_name": {"type": "string"}
      }
    },
    "action_required": {
      "type": "string",
      "enum": ["schedule_appointment", "cancel_appointment", "reschedule_appointment", "send_reminder", "escalate_to_human", "request_consent", "verify_identity", "none"],
      "description": "Action to be executed by downstream nodes"
    },
    "action_authorized": {
      "type": "boolean",
      "description": "Whether the action is authorized based on rules and constraints"
    },
    "authorization_rationale": {
      "type": "string",
      "description": "Clear explanation for authorization decision"
    },
    "message_to_patient": {
      "type": "string",
      "description": "Natural language response to send to the patient"
    },
    "audit_metadata": {
      "type": "object",
      "properties": {
        "timestamp": {"type": "string", "format": "date-time"},
        "session_id": {"type": "string"},
        "rules_applied": {"type": "array", "items": {"type": "string"}},
        "exceptions_detected": {"type": "array", "items": {"type": "string"}}
      }
    },
    "confidence_level": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Confidence score for intent and entity extraction"
    }
  },
  "required": ["workflow_state", "intent", "action_required", "action_authorized", "message_to_patient", "confidence_level"]
}

parameters.jsCode:
const intent = $input.item.json.intent;
const riskLevel = $input.item.json.patient_risk_level || 'low';
const confidenceLevel = $input.item.json.confidence_level;
const exceptionsDetected = $input.item.json.audit_metadata?.exceptions_detected || [];

// Priority scoring algorithm
let priorityScore = 50; // Base score

// Intent-based priority
const intentPriority = {
  'emergency_indicator': 100,
  'appointment_request': 30,
  'appointment_reschedule': 20,
  'appointment_cancel': 10,
  'medication_inquiry': 40,
  'consent_verification': 50,
  'identity_verification': 50
};

priorityScore += (intentPriority[intent] || 0);

// Risk level adjustment
const riskMultiplier = {
  'critical': 2.0,
  'high': 1.5,
  'medium': 1.0,
  'low': 0.8
};

priorityScore *= (riskMultiplier[riskLevel] || 1.0);

// Confidence penalty
if (confidenceLevel < 0.75) {
  priorityScore *= 0.7;
}

// Exception escalation
if (exceptionsDetected.length > 0) {
  priorityScore += (exceptionsDetected.length * 15);
}

return {
  ...($input.item.json),
  priority_score: Math.round(priorityScore),
  priority_tier: priorityScore >= 100 ? 'urgent' : priorityScore >= 60 ? 'high' : priorityScore >= 30 ? 'medium' : 'low'
};

const intent = $input.item.json.intent;
const dateTime = $input.item.json.entities.date_time;
const department = $input.item.json.entities.department;

// Business hours validation
const appointmentDate = new Date(dateTime);
const hour = appointmentDate.getHours();
const day = appointmentDate.getDay();

let violations = [];

// Rule 1: Business hours (8 AM - 6 PM)
if (hour < 8 || hour >= 18) {
  violations.push('appointment_outside_business_hours');
}

// Rule 2: No weekend appointments
if (day === 0 || day === 6) {
  violations.push('weekend_appointment_not_allowed');
}

// Rule 3: Department-specific rules
const emergencyDepts = ['emergency', 'trauma', 'urgent_care'];
if (emergencyDepts.includes(department?.toLowerCase()) && intent !== 'emergency_indicator') {
  violations.push('emergency_dept_requires_emergency_intent');
}

return {
  ...($input.item.json),
  business_rules_validation: {
    passed: violations.length === 0,
    violations: violations,
    validated_at: new Date().toISOString()
  }
};

const department = $input.params.department;
const requestedDateTime = $input.params.date_time;

// Simulated availability check (replace with actual API call)
const availableSlots = {
  'cardiology': ['2024-02-15T09:00:00Z', '2024-02-15T14:00:00Z'],
  'orthopedics': ['2024-02-16T10:00:00Z', '2024-02-16T15:00:00Z'],
  'neurology': ['2024-02-17T11:00:00Z']
};

const isAvailable = availableSlots[department?.toLowerCase()]?.includes(requestedDateTime);

return {
  department: department,
  requested_time: requestedDateTime,
  is_available: isAvailable,
  next_available_slots: availableSlots[department?.toLowerCase()] || [],
  checked_at: new Date().toISOString()
};

const patientName = $input.params.patient_name;
const actionType = $input.params.action_type;

// Simulated consent validation (replace with actual database query)
const consentRecords = {
  'John Doe': {
    consent_on_file: true,
    consent_types: ['appointment_scheduling', 'data_sharing'],
    expiration_date: '2025-12-31',
    last_updated: '2024-01-15'
  }
};

const patientConsent = consentRecords[patientName];
const hasValidConsent = patientConsent?.consent_on_file && 
                        patientConsent?.consent_types?.includes(actionType) &&
                        new Date(patientConsent?.expiration_date) > new Date();

return {
  patient_name: patientName,
  action_type: actionType,
  consent_valid: hasValidConsent,
  consent_types_on_file: patientConsent?.consent_types || [],
  expiration_date: patientConsent?.expiration_date,
  requires_renewal: !hasValidConsent,
  validated_at: new Date().toISOString()
};
